// Houses along a street hold money: {2, 7, 9, 3, 1}
// You can't rob two ADJACENT houses (triggers an alarm)
// What's the MAXIMUM total money you can rob?

// At house i, there are exactly two choices:
// SKIP house i entirely -> dp[i-1] (whatever we already had)
// ROB house i -> houses[i] + dp[i-2] (can't have also robbed i-1)

// dp[i] = max(dp[i-1], houses[i] + dp[i-2])

#include <iostream>
#include <vector>

using namespace std;

int rob(vector<int> &houses)
{
    int n = houses.size();
    if (n == 0) return 0;
    if (n == 1) return houses[0];

    vector<int> dp(n);
    dp[0] = houses[0];
    dp[1] = max(houses[0], houses[1]);

    for (int i = 2; i < n; i++)
    {
        dp[i] = max(dp[i - 1], houses[i] + dp[i - 2]);
    }

    return dp[n - 1];
}

int main()
{
    vector<int> houses = {2, 7, 9, 3, 1};

    cout << rob(houses) << endl;

    return 0;
}

