#include <vector>
#include <string>
#include <unordered_set>
#include <algorithm>

using namespace std;

bool wordBreak(string s, vector<string>& wordDict)
{
    unordered_set<string> dict(wordDict.begin(), wordDict.end());
    int maxLen = 0;
    for (auto &w : wordDict) maxLen = max(maxLen, (int)w.size());

    int n = s.size();
    vector<bool> dp(n + 1, false);
    dp[0] = true;

    for (int i = 1; i <= n; i++)
        for (int j = max(0, i - maxLen); j < i; j++)
            if (dp[j] && dict.count(s.substr(j, i - j)))
            {
                dp[i] = true;
                break;
            }

    return dp[n];
}

int main()
{
    string s = "leetcode";
    vector<string> wordDict = {"leet", "code"};

    cout << boolalpha << wordBreak(s, wordDict);

    return 0;
}

#include <iostream>
#include <vector>

using namespace std;

int climbStairs(int n)
{
    if (n <= 2) return n;

    vector<int> dp(n + 1);
    dp[1] = 1;
    dp[2] = 2;

    for (int i = 3; i <= n; i++)
        dp[i] = dp[i - 1] + dp[i - 2];

    return dp[n];
}

int main()
{
    cout << climbStairs(5);

    return 0;
}

#include <iostream>

using namespace std;

int climbStairs(int n)
{
    if (n <= 2) return n;

    int prev2 = 1, prev1 = 2;
    for (int i = 3; i <= n; i++)
    {
        int current = prev1 + prev2;
        prev2 = prev1;
        prev1 = current;
    }
    return prev1;
}

int main()
{
    cout << climbStairs(5);

    return 0;
}

